const item = $input.first();
const trigger = $('Watch B-Roll Transcripts Folder').first().json;

// Get transcript text from binary data
let transcript = '';
if (item.binary?.data) {
  transcript = Buffer.from(item.binary.data.data, 'base64').toString('utf-8');
} else if (item.json?.data) {
  transcript = item.json.data;
}

if (!transcript || transcript.trim().length < 20) {
  throw new Error('Transcript is empty or too short: ' + (transcript || '').substring(0, 50));
}

// Detect content type from parent folder path
// Expects: .../technical-walkthrough/file.txt or .../case-study/file.txt or .../podcast/file.txt
const parents = (trigger.parents || []).map(p => p.name?.toLowerCase() || '');
const folderPath = parents.join('/').toLowerCase();

let contentType = 'technical-walkthrough'; // default
if (folderPath.includes('case-study') || folderPath.includes('casestudy')) {
  contentType = 'case-study';
} else if (folderPath.includes('podcast')) {
  contentType = 'podcast';
} else if (folderPath.includes('technical') || folderPath.includes('walkthrough') || folderPath.includes('demo')) {
  contentType = 'technical-walkthrough';
}

// Parse speaker name and company from filename
// Convention: SpeakerName_Company_Title.txt  or just Title.txt
const fileName = trigger.name?.replace(/\.(txt|md|srt)$/i, '') || 'Untitled';
const parts = fileName.split('_').map(p => p.trim());

let speakerName = '';
let company = '';
let title = fileName;

if (parts.length >= 3) {
  speakerName = parts[0].replace(/([a-z])([A-Z])/g, '$1 $2');
  company = parts[1].replace(/([a-z])([A-Z])/g, '$1 $2');
  title = parts.slice(2).join(' ');
} else if (parts.length === 2) {
  speakerName = parts[0].replace(/([a-z])([A-Z])/g, '$1 $2');
  title = parts[1];
}

return [{
  json: {
    body: {
      contentType,
      transcript,
      videoUrl: '',
      speakerName,
      company,
      metrics: [],
      title
    },
    fileId: trigger.id,
    fileName: trigger.name,
    detectedContentType: contentType
  }
}];

const body = $input.first().json.body;
const contentType = body.contentType || 'technical-walkthrough';

const FLOWS = {
  'technical-walkthrough': '5 scenes: Hook(big-stat-reveal) -> Speaker(person-scorecard) -> HowItWorks(workflow-pipeline) -> Results(data-table/kpi-dashboard) -> Arch+CTA(node-graph+cta-comment)',
  'case-study': '6 scenes: HookStat(big-stat-reveal) -> ClientIntro(person-scorecard) -> Challenge(comparison-split) -> Solution(timeline-steps) -> Results(kpi-dashboard) -> Trust+CTA(logo-endorsement+cta-comment)',
  'podcast': '4-6 scenes: GuestIntro(person-scorecard) -> KeyStat(big-stat-reveal) -> TopicViz(varies) -> CTA(cta-comment)'
};

const systemPrompt = `You are a B-roll scene generator. Output JSON: { "meta": { "contentType": "${contentType}", "title": "<title>", "fps": 30, "width": 1080, "height": 1920, "talkingHeadUrl": "${body.videoUrl || ''}" }, "scenes": [{ "type": "<type>", "from": <frame>, "durationInFrames": <dur>, "data": {...} }], "textStrip": { "labels": [{ "from": <frame>, "label": "<text>" }] } }\n\nFlow: ${FLOWS[contentType] || FLOWS['technical-walkthrough']}\n\nTypes: big-stat-reveal({value,prefix?,suffix?,color,subtitle}), person-scorecard({name,title,badges[{value,label}]}), kpi-dashboard({header,cards[{label,value,color}]}), workflow-pipeline({header,rows[[{label,sub?,glow?}]]}), data-table({header,table:{columns,rows}}), node-graph({header,nodes[{label,x,y,color}],edges[{from,to}]}), timeline-steps({header,steps[{label,status}]}), comparison-split({left:{header,color,icon,items},right:{header,color,icon,items}}), logo-endorsement({header,logos[{name}]}), cta-comment({action,keyword})\n\nframe=sec*30. Colors: #00D4FF #00FF88 #FF4444 #FF8C00 #8B5CF6. Min 180 frames. ONLY JSON output.`;

const context = [body.speakerName ? `Speaker: ${body.speakerName}` : '', body.company ? `Company: ${body.company}` : ''].filter(Boolean).join('\n');
const userMessage = `${context ? context + '\n\n' : ''}Transcript:\n${body.transcript}`;

return [{ json: { ...($input.first().json), systemPrompt, userMessage, contentType, title: body.title } }];

const prev = $('Build Claude Prompt').first().json;
const response = $input.first().json;
const content = response.content?.[0]?.text || '';

let config;
try {
  config = JSON.parse(content);
} catch (e) {
  const match = content.match(/\{[\s\S]*\}/);
  if (match) config = JSON.parse(match[0]);
  else throw new Error('Failed to parse scene JSON');
}

const totalFrames = config.scenes.reduce((max, s) => Math.max(max, s.from + s.durationInFrames), 0);
if (!config.meta || !config.scenes?.length) throw new Error('Invalid config');

return [{ json: {
  config,
  totalFrames,
  totalSeconds: (totalFrames / 30).toFixed(1),
  sceneCount: config.scenes.length,
  sceneTypes: config.scenes.map(s => s.type),
  title: prev.title,
  contentType: prev.contentType,
  sourceFileId: prev.fileId,
  sourceFileName: prev.fileName,
  generatedAt: new Date().toISOString()
} }];
